import{_ as i,o as a,c as l,ag as r}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"QIServer Private AI Node","description":"","frontmatter":{"title":"QIServer Private AI Node","status":"active","date":"2026-04-19T00:00:00.000Z","layer":"compute","type":"runtime_profile","host":"qiserver","tailscale_name":"qiserver-1"},"headers":[],"relativePath":"10_core/40_service_apps/110_qiserver/runtime_profile.md","filePath":"10_core/40_service_apps/110_qiserver/runtime_profile.md"}'),t={name:"10_core/40_service_apps/110_qiserver/runtime_profile.md"};function o(n,e,s,c,d,h){return a(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="qiserver-private-ai-node" tabindex="-1">QIServer Private AI Node <a class="header-anchor" href="#qiserver-private-ai-node" aria-label="Permalink to &quot;QIServer Private AI Node&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>QIServer is the current machine-local QiOS compute node for private AI access, local model execution, and future ingestion/runtime work. It exists to offload AI and document-processing workload from the primary workstation and to serve as the first live QiOS local runtime host.</p><h2 id="why-this-node-exists" tabindex="-1">Why This Node Exists <a class="header-anchor" href="#why-this-node-exists" aria-label="Permalink to &quot;Why This Node Exists&quot;">​</a></h2><p>This node is the practical execution host for the local-runtime side of QiOS:</p><ul><li>private AI chat access</li><li>local model hosting</li><li>future ingestion and extraction</li><li>future chunking and embeddings</li><li>future local control-plane endpoints</li><li>future graph projection support</li></ul><p>It is not the canonical source of truth for records. Canonical truth remains in the cloud-side data model. Derived layers remain downstream.</p><h2 id="current-role" tabindex="-1">Current Role <a class="header-anchor" href="#current-role" aria-label="Permalink to &quot;Current Role&quot;">​</a></h2><h3 id="active-now" tabindex="-1">Active now <a class="header-anchor" href="#active-now" aria-label="Permalink to &quot;Active now&quot;">​</a></h3><ul><li>Tailscale-connected private server</li><li>Ollama running on host</li><li>Open WebUI running in Docker</li><li>Neo4j running in Docker</li><li>Tailscale Serve publishing Open WebUI privately to the tailnet</li></ul><h3 id="planned-next" tabindex="-1">Planned next <a class="header-anchor" href="#planned-next" aria-label="Permalink to &quot;Planned next&quot;">​</a></h3><ul><li>local Python API</li><li>inbox watcher</li><li>extraction pipeline</li><li>deterministic chunking</li><li>embedding worker</li><li>Conditional/Future: Supabase/pgvector upsert</li><li>Neo4j projection</li><li>queue/retry/status endpoints</li></ul><h2 id="runtime-position-in-qios" tabindex="-1">Runtime Position in QiOS <a class="header-anchor" href="#runtime-position-in-qios" aria-label="Permalink to &quot;Runtime Position in QiOS&quot;">​</a></h2><p>QIServer implements the <strong>local runtime</strong> side of QiOS, not the canonical cloud data layer.</p><h3 id="local-runtime-responsibilities" tabindex="-1">Local runtime responsibilities <a class="header-anchor" href="#local-runtime-responsibilities" aria-label="Permalink to &quot;Local runtime responsibilities&quot;">​</a></h3><ul><li>file watcher</li><li>ingest pipeline</li><li>OCR</li><li>extraction</li><li>chunking</li><li>embeddings</li><li>local API</li><li>machine-local state</li></ul><h3 id="cloud-side-responsibilities" tabindex="-1">Cloud-side responsibilities <a class="header-anchor" href="#cloud-side-responsibilities" aria-label="Permalink to &quot;Cloud-side responsibilities&quot;">​</a></h3><ul><li>canonical metadata</li><li>retrieval index in pgvector</li><li>app-facing APIs</li><li>review surfaces</li><li>Conditional/Future: tenant-aware data serving</li></ul><h3 id="boundary-rule" tabindex="-1">Boundary rule <a class="header-anchor" href="#boundary-rule" aria-label="Permalink to &quot;Boundary rule&quot;">​</a></h3><p>Local runtime writes registrations, metadata, and embeddings outward. Cloud runtime serves application surfaces. Graph, vector, and AI layers do not become canonical truth.</p><h2 id="current-access" tabindex="-1">Current Access <a class="header-anchor" href="#current-access" aria-label="Permalink to &quot;Current Access&quot;">​</a></h2><h3 id="private-access-surface" tabindex="-1">Private access surface <a class="header-anchor" href="#private-access-surface" aria-label="Permalink to &quot;Private access surface&quot;">​</a></h3><ul><li>Open WebUI: <code>https://qiserver-1.cerberus-sirius.ts.net</code></li></ul><h3 id="machine-identity" tabindex="-1">Machine identity <a class="header-anchor" href="#machine-identity" aria-label="Permalink to &quot;Machine identity&quot;">​</a></h3><ul><li>OS hostname: <code>qiserver</code></li><li>Tailscale machine: <code>qiserver-1</code></li><li>Tailscale IPv4: <code>100.121.111.106</code></li></ul><h2 id="current-local-services" tabindex="-1">Current Local Services <a class="header-anchor" href="#current-local-services" aria-label="Permalink to &quot;Current Local Services&quot;">​</a></h2><h3 id="host-service" tabindex="-1">Host service <a class="header-anchor" href="#host-service" aria-label="Permalink to &quot;Host service&quot;">​</a></h3><ul><li>Ollama API: <code>http://127.0.0.1:11434</code></li></ul><h3 id="docker-services" tabindex="-1">Docker services <a class="header-anchor" href="#docker-services" aria-label="Permalink to &quot;Docker services&quot;">​</a></h3><ul><li>Open WebUI: <code>http://127.0.0.1:3000</code></li><li>Neo4j Browser: <code>http://127.0.0.1:7474</code></li><li>Neo4j Bolt: <code>bolt://127.0.0.1:7687</code></li></ul><h2 id="current-service-topology" tabindex="-1">Current Service Topology <a class="header-anchor" href="#current-service-topology" aria-label="Permalink to &quot;Current Service Topology&quot;">​</a></h2><h3 id="host" tabindex="-1">Host <a class="header-anchor" href="#host" aria-label="Permalink to &quot;Host&quot;">​</a></h3><ul><li>Ubuntu server</li><li>Tailscale</li><li>Ollama</li></ul><h3 id="containers" tabindex="-1">Containers <a class="header-anchor" href="#containers" aria-label="Permalink to &quot;Containers&quot;">​</a></h3><ul><li>Open WebUI</li><li>Neo4j</li></ul><h3 id="network-pattern" tabindex="-1">Network pattern <a class="header-anchor" href="#network-pattern" aria-label="Permalink to &quot;Network pattern&quot;">​</a></h3><ul><li>services bind locally</li><li>Tailscale Serve proxies Open WebUI privately to the tailnet</li><li>raw backend services are not publicly exposed</li></ul><h2 id="current-paths" tabindex="-1">Current Paths <a class="header-anchor" href="#current-paths" aria-label="Permalink to &quot;Current Paths&quot;">​</a></h2><h3 id="server-paths" tabindex="-1">Server paths <a class="header-anchor" href="#server-paths" aria-label="Permalink to &quot;Server paths&quot;">​</a></h3><ul><li>QiOS root: <code>/srv/qios</code></li><li>compose: <code>/srv/qios/compose</code></li><li>server runbook: <code>/srv/qios/docs/000_RUN_ME_FIRST.md</code></li></ul><h3 id="data-paths" tabindex="-1">Data paths <a class="header-anchor" href="#data-paths" aria-label="Permalink to &quot;Data paths&quot;">​</a></h3><ul><li>data root: <code>/srv/qidata</code></li><li>inbox: <code>/srv/qidata/inbox</code></li><li>processing: <code>/srv/qidata/processing</code></li><li>reviewed: <code>/srv/qidata/reviewed</code></li><li>failed: <code>/srv/qidata/failed</code></li><li>manifests: <code>/srv/qidata/manifests</code></li><li>extracted text: <code>/srv/qidata/extracted_text</code></li><li>embeddings cache: <code>/srv/qidata/embeddings_cache</code></li><li>logs: <code>/srv/qidata/logs</code></li><li>model cache: <code>/srv/qidata/model_cache</code></li><li>exports: <code>/srv/qidata/exports</code></li></ul><h2 id="current-models" tabindex="-1">Current Models <a class="header-anchor" href="#current-models" aria-label="Permalink to &quot;Current Models&quot;">​</a></h2><h3 id="chat-model" tabindex="-1">Chat model <a class="header-anchor" href="#chat-model" aria-label="Permalink to &quot;Chat model&quot;">​</a></h3><ul><li><code>llama3.2:latest</code></li></ul><h3 id="embedding-model" tabindex="-1">Embedding model <a class="header-anchor" href="#embedding-model" aria-label="Permalink to &quot;Embedding model&quot;">​</a></h3><ul><li><code>embeddinggemma:latest</code></li></ul><h2 id="model-rule" tabindex="-1">Model Rule <a class="header-anchor" href="#model-rule" aria-label="Permalink to &quot;Model Rule&quot;">​</a></h2><p><code>llama3.2</code> is the chat/default interaction model.</p><p><code>embeddinggemma</code> is not a general chat default. It is reserved for embedding, retrieval, and vectorization work.</p><h2 id="architectural-constraints" tabindex="-1">Architectural Constraints <a class="header-anchor" href="#architectural-constraints" aria-label="Permalink to &quot;Architectural Constraints&quot;">​</a></h2><ol><li>This node is compute infrastructure, not canonical record authority.</li><li>Graph and vector outputs are derived.</li><li>No ingestion flow should bypass canonical registration.</li><li>No downstream layer should redefine identity.</li><li>Runtime memory for operation lives both here and in the machine-local runbook.</li></ol><h2 id="relationship-to-existing-blueprint-sections" tabindex="-1">Relationship to Existing Blueprint Sections <a class="header-anchor" href="#relationship-to-existing-blueprint-sections" aria-label="Permalink to &quot;Relationship to Existing Blueprint Sections&quot;">​</a></h2><p>This node operationalizes the following already-defined blueprint concepts:</p><ul><li>local runtime</li><li>local API</li><li>embeddings as local subprocess</li><li>Neo4j as derived graph</li><li>Local Admin Control Plane</li><li>Spine milestone: local inbox -&gt; registration -&gt; extraction -&gt; embedding -&gt; retrieval</li></ul><p>This file does not replace those sections. It records the concrete live node now implementing them.</p><h2 id="operational-re-entry" tabindex="-1">Operational Re-entry <a class="header-anchor" href="#operational-re-entry" aria-label="Permalink to &quot;Operational Re-entry&quot;">​</a></h2><p>If operator context is lost, begin with:</p><ul><li><code>/srv/qios/docs/000_RUN_ME_FIRST.md</code></li><li><code>bash /usr/local/bin/qiserver-status</code></li></ul><h2 id="immediate-next-build" tabindex="-1">Immediate Next Build <a class="header-anchor" href="#immediate-next-build" aria-label="Permalink to &quot;Immediate Next Build&quot;">​</a></h2><ol><li>create local Python API structure</li><li>implement <code>/status</code>, <code>/queue</code>, <code>/ingest</code>, <code>/retry</code></li><li>build inbox watcher against <code>/srv/qidata/inbox</code></li><li>extract text into canonical pipeline flow</li><li>chunk deterministically</li><li>call Ollama embeddings endpoint</li><li>upsert to canonical retrieval layer</li><li>project derived graph records into Neo4j</li></ol><h2 id="change-log" tabindex="-1">Change Log <a class="header-anchor" href="#change-log" aria-label="Permalink to &quot;Change Log&quot;">​</a></h2><h3 id="_2026-04-19" tabindex="-1">2026-04-19 <a class="header-anchor" href="#_2026-04-19" aria-label="Permalink to &quot;2026-04-19&quot;">​</a></h3><ul><li>Ubuntu server brought online</li><li>Tailscale configured</li><li>Docker installed and running</li><li>Ollama installed and serving locally</li><li><code>llama3.2</code> pulled</li><li><code>embeddinggemma</code> pulled</li><li>Open WebUI deployed in Docker</li><li>Neo4j deployed in Docker</li><li>Tailscale Serve configured for private Open WebUI access</li><li>server-local operator runbook created</li><li>status command created</li></ul><h2 id="active-runtime" tabindex="-1">Active Runtime <a class="header-anchor" href="#active-runtime" aria-label="Permalink to &quot;Active Runtime&quot;">​</a></h2><ul><li><strong>qiserver</strong> is the current active runtime.</li></ul><h2 id="path-doctrine" tabindex="-1">Path Doctrine <a class="header-anchor" href="#path-doctrine" aria-label="Permalink to &quot;Path Doctrine&quot;">​</a></h2><ul><li><code>/srv/qios/repos</code>: For cloned Git repos and coding work.</li><li><code>/srv/qios/stacks</code>: For Docker Compose runtime stacks. Do not create nested Git repos inside <code>/srv/qios/stacks</code>.</li><li><code>/srv/qios/data</code>: For persistent app data.</li></ul><h2 id="service-runtime-facts" tabindex="-1">Service / Runtime Facts <a class="header-anchor" href="#service-runtime-facts" aria-label="Permalink to &quot;Service / Runtime Facts&quot;">​</a></h2><ul><li><strong>NocoDB</strong>: Runs locally at <code>127.0.0.1:8088</code>.</li><li><strong>Open WebUI</strong>: Runs locally at <code>127.0.0.1:3000</code>.</li><li><strong>Private Server Launcher (gethomepage)</strong>: Runs locally at <code>127.0.0.1:3001</code>. <strong>Warning:</strong> This is for local/tailnet use only and is separate from the public <code>access.qially.com</code> portal.</li><li><strong>Portainer</strong>: Runs locally at <code>127.0.0.1:9443</code> and is an admin service.</li><li><strong>Ollama</strong>: Installed on qiserver and locked to <code>127.0.0.1:11434</code>.</li></ul>',70)])])}const m=i(t,[["render",o]]);export{p as __pageData,m as default};
